import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { NamedRegionRangeProvider, NamedRegion } from '../../browser/namedRegionProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

interface RangesLimitReporter {
	limit: number;
	update(computed: number, limited: number | false): void;
}

class TestRangesLimitReporter implements RangesLimitReporter {
	limit = 5000;
	update(computed: number, limited: number | false): void {
		// no-op for testing
	}
}

suite('Named Region Provider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Detects simple named region', async () => {
		const lines = [
			'// #region MySection',
			'const a = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		assert.strictEqual(result !== null, true, 'Should return a FoldingRegions');
		assert.strictEqual(result?.length, 1, 'Should have 1 region');
		assert.strictEqual(result?.getStartLineNumber(0), 1, 'Start line should be 1');
		assert.strictEqual(result?.getEndLineNumber(0), 3, 'End line should be 3');

		const namedRegions = provider.getNamedRegions();
		assert.strictEqual(namedRegions.length, 1, 'Should have 1 named region');
		assert.strictEqual(namedRegions[0].name, 'MySection', 'Region name should be MySection');
		assert.strictEqual(namedRegions[0].startLineNumber, 1, 'Start line number should be 1');
		assert.strictEqual(namedRegions[0].endLineNumber, 3, 'End line number should be 3');

		model.dispose();
	});

	test('Detects multiple named regions', async () => {
		const lines = [
			'// #region FirstSection',
			'const a = 1;',
			'// #endregion',
			'',
			'// #region SecondSection',
			'const b = 2;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
