function computeNamedRegions(model: ITextModel): NamedRegion[] {
	const regions: NamedRegion[] = [];
	const stack: Array<{ name: string; startLine: number }> = [];
	const lineCount = model.getLineCount();

	// Regular expressions for #region and #endregion markers
	// Supports various comment styles: //, #, --, /*, etc.
	const regionStartPattern = /#region\s+(.+?)(?:\s*$|\s*\*|$)/;
	const regionEndPattern = /#endregion/;

	for (let lineNumber = 1; lineNumber <= lineCount; lineNumber++) {
		const lineContent = model.getLineContent(lineNumber);

		const startMatch = lineContent.match(regionStartPattern);
		if (startMatch) {
			const regionName = startMatch[1].trim();
			stack.push({ name: regionName, startLine: lineNumber });
			continue;
		}

		if (regionEndPattern.test(lineContent)) {
			if (stack.length > 0) {
				const region = stack.pop()!;
				regions.push({
					name: region.name,
					startLineNumber: region.startLine,
					endLineNumber: lineNumber
				});
			}
		}
	}

	return regions;
}

